    except:
        continue

print(f"Extracted fork counts for {len(forks)} projects")

# Combine and get top 5
results = []
for p in mapped:
    proj = p['ProjectName']
    if proj in forks:
        results.append({
            'PackageName': p['Name'],
            'Version': p['Version'],
            'ProjectName': proj,
            'Forks': forks[proj]
        })

top_5 = sorted(results, key=lambda x: x['Forks'], reverse=True)[:5]

# Output result
result = {
    'total_packages': len(results),
    'top_5': top_5
}

print('__RESULT__:')
print(json.dumps(result))"}
